use std::cmp::Ordering;

/// Merges a list of intervals, returning a new vector of non-overlapping merged intervals.
///
/// # Arguments
///
/// * `intervals` - A vector of tuples where each tuple contains two integers: the start and end of an interval.
///
/// # Returns
///
/// A new vector of tuples representing merged intervals. Each interval is formed by the minimum start and maximum end of any overlapping intervals.
///
/// # Examples
///
/// ```rust
/// let intervals = vec![(1, 3), (2, 4), (6, 8), (7, 9)];
/// let merged = merge_intervals(intervals);
/// assert_eq!(merged, vec![(1, 9)]);
/// ```
fn merge_intervals(intervals: Vec<(i32, i32)>) -> Vec<(i32, i32)> {
    if intervals.is_empty() {
        return Vec::new();
    }

    // Sort intervals by start time
    let mut sorted_intervals: Vec<(i32, i32)> = intervals.into_iter().sorted_by(|a, b| {
        if a.0 < b.0 { Ordering::Less } else if a.0 > b.0 { Ordering::Greater } else { Ordering::Equal }
    }).collect();

    let mut merged: Vec<(i32, i32)> = vec![];

    // Initialize with the first interval
    let mut current_start = sorted_intervals[0].0;
    let mut current_end = sorted_intervals[0].1;

    for (start, end) in sorted_intervals.iter().skip(1) {
        if start <= current_end {
            // Overlapping, merge
            current_end = std::cmp::max(current_end, end);
        } else {
            // No overlap, add current interval to merged list
            merged.push((current_start, current_end));
            current_start = start;
            current_end = end;
        }
    }

    // Add the last interval
    merged.push((current_start, current_end));

    merged
}
